import time
from datetime import timedelta

def generar_reloj_digital():
    while True:
        hora = time.localtime()
        minutos = hora.tm_min
        segundos = hora.tm_sec
        if minutos < 10:
            minutos_str = f"0{minutos}"
        else:
            minutos_str = str(minutos)

        if segundos < 10:
            segundos_str = f"0{segundos}"
        else:
            segundos_str = str(segundos)

        print(f"{hora.tm_hour}:{minutos_str}:{segundos_str}", end="\r")

if __name__ == "__main__":
    generar_reloj_digital()
